#include <iostream>

class MyString {
private:
    char* data;
    size_t len;

    size_t manual_strlen(const char* s) const {
        if (!s) return 0;
        size_t count = 0;
        while (s[count] != '\0') {
            count++;
        }
        return count;
    }

    void manual_strcpy(char* dest, const char* src) const {
        if (!dest || !src) return;
        size_t i = 0;
        while (src[i] != '\0') {
            dest[i] = src[i];
            i++;
        }
        dest[i] = '\0';
    }

public:
    MyString() : data(nullptr), len(0) {
        data = new char[1];
        data[0] = '\0';
    }

    MyString(const char* s) {
        if (!s) {
            len = 0;
            data = new char[1];
            data[0] = '\0';
            return;
        }
        len = manual_strlen(s);
        data = new char[len + 1];
        manual_strcpy(data, s);
    }

    MyString(const MyString& other) {
        len = other.len;
        data = new char[len + 1];
        manual_strcpy(data, other.data);
    }

    ~MyString() {
        delete[] data;
    }

    void display() const {
        if (data) {
            size_t i = 0;
            while (data[i] != '\0') {
                std::cout << data[i];
                i++;
            }
        }
    }

    size_t getLength() const {
        std::cout << len;
    }
};

int main() {
    MyString s1("Hello, World!");
    std::cout << "s1: ";
    s1.display();
    std::cout << " (Length: "; s1.getLength(); std::cout << ")\n";

    MyString s2 = s1;
    std::cout << "s2 (copy of s1): ";
    s2.display();
    std::cout << " (Length: "; s2.getLength(); std::cout << ")\n";

    MyString s3("C++ Programming");
    std::cout << "s3: ";
    s3.display();
    std::cout << " (Length: "; s3.getLength(); std::cout << ")\n";

    MyString s4("");
    std::cout << "s4 (empty): ";
    s4.display();
    std::cout << " (Length: "; s4.getLength(); std::cout << ")\n";

    MyString s5(nullptr);
    std::cout << "s5 (from nullptr): ";
    s5.display();
    std::cout << " (Length: "; s5.getLength(); std::cout << ")\n";

    return 0;
}
